### 6. Root Layout

**src/app/layout.tsx**
```tsx
import type { Metadata } from 'next'
import { Inter, Poppins } from 'next/font/google'
import './globals.css'

const inter = Inter({ 
  subsets: ['latin'],
  variable: '--font-inter',
  display: 'swap',
})

const poppins = Poppins({ 
  subsets: ['latin'],
  variable: '--font-poppins',
  weight: ['300', '400', '500', '600', '700'],
  display: 'swap',
})

export const metadata: Metadata = {
  title: {
    template: '%s | Premium Auto Sales',
    default: 'Premium Auto Sales - Quality Used & New Cars',
  },
  description: 'Find your perfect car at Premium Auto Sales. Browse our extensive inventory of quality used and new vehicles with competitive pricing and financing options.',
  keywords: ['used cars', 'new cars', 'auto sales', 'car dealership', 'vehicle financing', 'auto loans'],
  authors: [{ name: 'Premium Auto Sales' }],
  creator: 'Premium Auto Sales',
  publisher: 'Premium Auto Sales',
  metadataBase: new URL('https://premium-auto-sales.vercel.app'),
  alternates: {
    canonical: '/',
  },
  openGraph: {
    type: 'website',
    locale: 'en_US',
    url: 'https://premium-auto-sales.vercel.app',
    title: 'Premium Auto Sales - Quality Used & New Cars',
    description: 'Find your perfect car at Premium Auto Sales. Browse our extensive inventory of quality used and new vehicles.',
    siteName: 'Premium Auto Sales',
    images: [
      {
        url: '/images/og-image.jpg',
        width: 1200,
        height: 630,
        alt: 'Premium Auto Sales',
      },
    ],
  },
  twitter: {
    card: 'summary_large_image',
    title: 'Premium Auto Sales - Quality Used & New Cars',
    description: 'Find your perfect car at Premium Auto Sales. Browse our extensive inventory of quality used and new vehicles.',
    images: ['/images/og-image.jpg'],
  },
  robots: {
    index: true,
    follow: true,
    googleBot: {
      index: true,
      follow: true,
      'max-video-preview': -1,
      'max-image-preview': 'large',
      'max-snippet': -1,
    },
  },
}

export default function RootLayout({
  children,
}: {
  children: React.ReactNode
}) {
  return (
    <html lang="en" className={`${inter.variable} ${poppins.variable}`}>
      <head>
        <link rel="icon" href="/favicon.ico" sizes="any" />
        <link rel="icon" href="/icon.svg" type="image/svg+xml" />
        <link rel="apple-touch-icon" href="/apple-touch-icon.png" />
        <meta name="theme-color" content="#1d4ed8" />
      </head>
      <body className={`${inter.className} antialiased bg-white text-gray-900`}>
        <div className="min-h-screen flex flex-col">
          {children}
        </div>
      </body>
    </html>
  )
}
```

